import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.CMWvBNEy.js";const h=JSON.parse('{"title":"AI Agentic Harness Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/agentic-harness.md","filePath":"guide/agentic-harness.md"}'),i={name:"guide/agentic-harness.md"};function r(s,e,c,l,d,g){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-agentic-harness-guide" tabindex="-1">AI Agentic Harness Guide <a class="header-anchor" href="#ai-agentic-harness-guide" aria-label="Permalink to &quot;AI Agentic Harness Guide&quot;">​</a></h1><p>Mocking GUI is developed with high quality and consistency through an <strong>AI Agentic Harness</strong> system. All contributors can leverage specialized agents and workflows to contribute to the project more easily and systematically.</p><h2 id="🎯-mission-map-workflow-selection-guide" tabindex="-1">🎯 Mission Map: Workflow Selection Guide <a class="header-anchor" href="#🎯-mission-map-workflow-selection-guide" aria-label="Permalink to &quot;🎯 Mission Map: Workflow Selection Guide&quot;">​</a></h2><p>Choose the agent mission that matches your contribution goal.</p><h3 id="case-1-improve-or-add-features-to-mocking-gui" tabindex="-1">Case 1: Improve or Add Features to Mocking GUI <a class="header-anchor" href="#case-1-improve-or-add-features-to-mocking-gui" aria-label="Permalink to &quot;Case 1: Improve or Add Features to Mocking GUI&quot;">​</a></h3><ul><li><strong>When</strong>: You want to modify the GUI panel UI or add new functionality to the core engine.</li><li><strong>How</strong>: Run <code>/harness-dev-pipeline</code> in your AI assistant.</li><li><strong>Result</strong>: The <code>harness-dev-pipeline</code> workflow orchestrates four sequential phases — Product Planning → Architecture Design → Implementation → Quality Verification — with each phase delegated to a specialized sub-agent.</li></ul><h3 id="case-2-generate-service-mocking-handlers" tabindex="-1">Case 2: Generate Service Mocking Handlers <a class="header-anchor" href="#case-2-generate-service-mocking-handlers" aria-label="Permalink to &quot;Case 2: Generate Service Mocking Handlers&quot;">​</a></h3><ul><li><strong>When</strong>: You want to build high-quality mocking handlers and data based on an API specification.</li><li><strong>How</strong>: <code>@handler-specialist, generate handlers based on [Swagger URL or API spec].</code></li><li><strong>Result</strong>: A complete handler set following the 4-Layer architecture (Handlers, Constants, Factories, Utils) is generated in compliance with the <code>handler-specification</code> standard.</li></ul><h3 id="case-3-project-onboarding-and-migration" tabindex="-1">Case 3: Project Onboarding and Migration <a class="header-anchor" href="#case-3-project-onboarding-and-migration" aria-label="Permalink to &quot;Case 3: Project Onboarding and Migration&quot;">​</a></h3><ul><li><strong>When</strong>: You want to integrate Mocking GUI into an existing project, or refactor an existing MSW setup to the Mocking GUI standard.</li><li><strong>How</strong>: Run <code>/technical-solution-support</code> in your AI assistant.</li><li><strong>Result</strong>: The <code>technical-solution-support</code> workflow analyzes your project environment and provides an optimized migration strategy and onboarding guide.</li></ul><h2 id="🚀-agentic-quality-gate" tabindex="-1">🚀 Agentic Quality Gate <a class="header-anchor" href="#🚀-agentic-quality-gate" aria-label="Permalink to &quot;🚀 Agentic Quality Gate&quot;">​</a></h2><p>Every workflow automatically performs the following to reduce contributor burden:</p><ol><li><strong>Automated Test &amp; Build</strong>: Runs <code>vitest</code> and <code>build</code> checks to ensure changes don&#39;t break existing functionality.</li><li><strong>Technical Standards Enforcement</strong>: Validates real-time compliance with <code>technical-guardrail</code> rules and architecture standards.</li><li><strong>Documentation Automation</strong>: Keeps technical docs and reports in sync with code changes.</li></ol><p>Contributors only need to <strong>give the agent a clear mission</strong> and <strong>review and approve the decision report</strong> generated at each phase.</p>',14)])])}const p=a(i,[["render",r]]);export{h as __pageData,p as default};
